var coc = parseFloat(sensorSize);
    var distMM = focusDist * 304.8;
    var h = (focalLength * focalLength) / (aperture * coc);
    var nearMM = (h * distMM) / (h + (distMM - focalLength));
    var farMM = distMM < h ? (h * distMM) / (h - (distMM - focalLength)) : Infinity;
    var dofMM = farMM === Infinity ? Infinity : farMM - nearMM;
    var nearFt = nearMM / 304.8;
    var farFt = farMM === Infinity ? Infinity : farMM / 304.8;
    var dofFt = dofMM === Infinity ? Infinity : dofMM / 304.8;
    var hFt = h / 304.8;
    document.getElementById('dof').textContent = dofFt === Infinity ? 'Infinite (beyond hyperfocal)' : fmt(dofFt, 2) + ' ft (' + fmt(dofFt * 12, 0) + ' in)';
    document.getElementById('nearLimit').textContent = fmt(nearFt, 2) + ' ft';
    document.getElementById('farLimit').textContent = farFt === Infinity ? 'Infinity' : fmt(farFt, 2) + ' ft';
    document.getElementById('hyperfocal').textContent = fmt(hFt, 1) + ' ft (' + fmt(hFt * 0.3048, 1) + ' m)';

