var mileageDeduction = mileage * 0.67;
    var netIncome = quarterlyIncome - quarterlyExpenses - mileageDeduction;
    var seTax = netIncome * 0.9235 * 0.153;
    var seDeduction = seTax * 0.5;
    var taxableIncome = netIncome - seDeduction;
    var annualTaxable = (taxableIncome * 4) + otherIncome;
    var taxRate;
    if (annualTaxable <= 11600) taxRate = 0.10;
    else if (annualTaxable <= 47150) taxRate = 0.12;
    else if (annualTaxable <= 100525) taxRate = 0.22;
    else if (annualTaxable <= 191950) taxRate = 0.24;
    else taxRate = 0.32;
    var incomeTax = taxableIncome * taxRate;
    var totalPayment = Math.max(0, seTax + incomeTax);
    var effectiveRate = quarterlyIncome > 0 ? (totalPayment / quarterlyIncome) * 100 : 0;
    document.getElementById('netIncome').textContent = dollar(netIncome);
    document.getElementById('seTax').textContent = dollar(Math.max(0, seTax));
    document.getElementById('incomeTax').textContent = dollar(Math.max(0, incomeTax));
    document.getElementById('totalPayment').textContent = dollar(totalPayment);
    document.getElementById('effectiveRate').textContent = fmt(effectiveRate, 1) + '%';

function reduceToSingle(n) {
      while (n > 9 && n !== 11 && n !== 22 && n !== 33) {
        var sum = 0; var s = n.toString();
        for (var i = 0; i < s.length; i++) sum += parseInt(s[i]);
        n = sum;
      }
      return n;
    }
