var brownCN = parseInt(brownType);
    var greenCN = parseInt(greenType);
    var totalCarbon = brownLbs * brownCN + greenLbs * greenCN;
    var totalNitrogen = brownLbs + greenLbs;
    var ratio = totalCarbon / totalNitrogen;
    var assessment, adjustment, time;
    if (ratio >= 25 && ratio <= 35) {
      assessment = 'Ideal range! Your compost should decompose efficiently.';
      adjustment = 'No adjustment needed. Maintain moisture like a wrung-out sponge.';
      time = '2-4 months (turned regularly)';
    } else if (ratio > 35) {
      var greenNeeded = (totalCarbon - 30 * totalNitrogen) / (30 - greenCN);
      assessment = 'Too carbon-heavy (slow decomposition).';
      adjustment = 'Add ' + fmt(Math.max(0, greenNeeded), 0) + ' lbs more green material to reach ideal 30:1.';
      time = '6-12 months (slow due to excess carbon)';
    } else {
      var brownNeeded = (30 * totalNitrogen - totalCarbon) / (brownCN - 30);
      assessment = 'Too nitrogen-heavy (may smell bad).';
      adjustment = 'Add ' + fmt(Math.max(0, brownNeeded), 0) + ' lbs more brown material to reach ideal 30:1.';
      time = '1-2 months (fast but may be smelly)';
    }
    document.getElementById('currentRatio').textContent = fmt(ratio, 0) + ':1 (ideal: 25-35:1)';
    document.getElementById('idealAssessment').textContent = assessment;
    document.getElementById('adjustment').textContent = adjustment;
    document.getElementById('compostTime').textContent = time;
